            {/* Left Panel Collapsed Tab */}
            {!leftPanelVisible && (
              <div 
                onClick={() => setLeftPanelVisible(true)}
                style={{
                  width: '32px',
                  backgroundColor: '#0066cc',
                  borderRight: '2px solid #d6dbdf',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  position: 'relative',
                  zIndex: 1,
                  transition: 'all 0.3s ease'
