                  color: 'white',
                  fontSize: '14px',
                  fontWeight: '600',
                  writingMode: 'vertical-lr',
                  textOrientation: 'mixed',
                  fontFamily: '"Segoe UI", "Arial", sans-serif',
                  userSelect: 'none',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}>
                  <span style={{ fontSize: '12px' }}>▶</span>
                  <span>TEMPLATES</span>
                </div>
              </div>
