                      color: 'white',
                      fontSize: '14px',
                      fontWeight: '600',
                      fontFamily: '"Segoe UI", "Arial", sans-serif',
                      userSelect: 'none',
                      cursor: 'pointer',
                      transition: 'background-color 0.2s ease'
