                    overflow: 'auto',
                    transition: 'width 0.3s ease, z-index 0s 0.3s',
                    position: 'relative',
                    zIndex: 1,
                    minWidth: '250px',
                    boxShadow: 'inset 1px 0 0 rgba(0,102,204,0.1)',
                    display: 'flex',
                    flexDirection: 'column'
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.width = '350px';
                    e.currentTarget.style.zIndex = '10';
                    e.currentTarget.style.boxShadow = '-2px 0 12px rgba(0,102,204,0.15), inset 1px 0 0 rgba(0,102,204,0.2)';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.width = '250px';
                    e.currentTarget.style.zIndex = '1';
                    e.currentTarget.style.boxShadow = 'inset 1px 0 0 rgba(0,102,204,0.1)';
