                      color: 'white',
                      fontSize: '14px',
                      fontWeight: '600',
                      fontFamily: '"Segoe UI", "Arial", sans-serif',
                      userSelect: 'none',
                      cursor: 'pointer',
                      transition: 'background-color 0.2s ease'
                    }}
                    onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#0052a3'}
