                      backgroundConfig={backgroundConfig}
                      onBackgroundConfigChange={setBackgroundConfig}
                      dataConnections={dataConnections}
                      onWindowsChange={setWindows}
                      onDataConnectionsChange={setDataConnections}
                    />
                  </div>
                </div>
              )}

              {/* Collapsed Layers Tab */}
              {!layersVisible && (
                <div 
                  onClick={() => setLayersVisible(true)}
                  style={{
                    width: '32px',
                    backgroundColor: '#0066cc',
                    borderLeft: '2px solid #d6dbdf',
                    cursor: 'pointer',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    position: 'relative',
                    zIndex: 1,
                    transition: 'all 0.3s ease'
                  }}
                >
                  <div style={{
                    color: 'white',
                    fontSize: '14px',
                    fontWeight: '600',
                    writingMode: 'vertical-lr',
                    textOrientation: 'mixed',
                    fontFamily: '"Segoe UI", "Arial", sans-serif',
                    userSelect: 'none',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '8px'
                  }}>
                    <span>LAYERS</span>
                    <span style={{ fontSize: '12px' }}>◀</span>
                  </div>
                </div>
              )}

              {/* Collapsed Export Tab */}
              {!exportVisible && (
                <div 
                  onClick={() => setExportVisible(true)}
                  style={{
                    width: '32px',
                    backgroundColor: '#0066cc',
                    borderLeft: '2px solid #d6dbdf',
                    cursor: 'pointer',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    position: 'relative',
                    zIndex: 1,
                    transition: 'all 0.3s ease'
                  }}
                >
                  <div style={{
                    color: 'white',
                    fontSize: '14px',
                    fontWeight: '600',
                    writingMode: 'vertical-lr',
                    textOrientation: 'mixed',
                    fontFamily: '"Segoe UI", "Arial", sans-serif',
                    userSelect: 'none',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '8px'
                  }}>
                    <span>EXPORT</span>
                    <span style={{ fontSize: '12px' }}>◀</span>
                  </div>
                </div>
              )}
            </>
          </>
        ) : activeTab === 'data' ? (
          <div style={{ 
            flex: 1, 
            backgroundColor: '#f7f8fa',
            fontFamily: '"Segoe UI", "Arial", sans-serif'
          }}>
            <DataConnections
              dataConnections={dataConnections}
              onDataConnectionsChange={setDataConnections}
            />
          </div>
        ) : activeTab === 'variables' ? (
          <div style={{ 
            flex: 1, 
            backgroundColor: '#f7f8fa',
            fontFamily: '"Segoe UI", "Arial", sans-serif'
          }}>
            <VariablesView
              dataConnections={dataConnections}
              onDataConnectionsChange={setDataConnections}
            />
          </div>
        ) : activeTab === 'editor' ? (
          <CodeEditor 
            builderPages={builderPages}
            activeBuilderPageId={activeBuilderPageId}
            dataConnections={dataConnections}
            onBuilderPagesChange={setBuilderPages}
          />
        ) : activeTab === 'gateway' ? (
          <GatewayBuilder />
        ) : null}
      </div>
    </div>
  );
};

export default App;
